async function r(t,e={}){const n=await fetch(`${t}`,{...e,headers:{"Content-Type":"application/json",...e.headers}});if(!n.ok){const a=await n.text().catch(()=>"");throw new Error(a||`Error ${n.status}`)}return n.json()}function o(t){return r(t)}function i(t,e){return r(t,{method:"POST",body:JSON.stringify(e)})}function s(t,e){return r(t,{method:"PUT",body:JSON.stringify(e)})}function c(t){return r(t,{method:"DELETE"})}export{o as a,i as b,r as c,c as d,s as e};
